1	import { describe, it, expect } from "vitest";
2	import { moveRover } from "./mars-rover.js";
3	
4	describe("Mars Rover", () => {
5	  it("should return initial position and heading when given no commands", () => {
6	    expect(moveRover({ x: 0, y: 0, heading: "N" }, "")).toEqual({ x: 0, y: 0, heading: "N" });
7	  });
8	  it("should move forward one step north when facing north", () => {
9	    expect(moveRover({ x: 0, y: 0, heading: "N" }, "F")).toEqual({ x: 0, y: 1, heading: "N" });
10	  });
11	  it("should move forward one step east when facing east", () => {
12	    expect(moveRover({ x: 0, y: 0, heading: "E" }, "F")).toEqual({ x: 1, y: 0, heading: "E" });
13	  });
14	  it("should move forward one step south when facing south", () => {
15	    expect(moveRover({ x: 0, y: 0, heading: "S" }, "F")).toEqual({ x: 0, y: -1, heading: "S" });
16	  });
17	  it("should move forward one step west when facing west", () => {
18	    expect(moveRover({ x: 0, y: 0, heading: "W" }, "F")).toEqual({ x: -1, y: 0, heading: "W" });
19	  });
20	  it("should turn left from north to west", () => {
21	    expect(moveRover({ x: 0, y: 0, heading: "N" }, "L")).toEqual({ x: 0, y: 0, heading: "W" });
22	  });
23	  it.todo("should turn right from north to east");
24	  it.todo("should execute a sequence of multiple commands");
25	});
