1	const forwardDelta: Record<string, { dx: number; dy: number }> = {
2	  N: { dx: 0, dy: 1 },
3	  E: { dx: 1, dy: 0 },
4	  S: { dx: 0, dy: -1 },
5	  W: { dx: -1, dy: 0 },
6	};
7	
8	const leftTurn: Record<string, string> = {
9	  N: "W",
10	  W: "S",
11	  S: "E",
12	  E: "N",
13	};
14	
15	export function moveRover(rover: { x: number; y: number; heading: string }, commands: string) {
16	  if (commands === "F") {
17	    const { dx, dy } = forwardDelta[rover.heading];
18	    return { ...rover, x: rover.x + dx, y: rover.y + dy };
19	  }
20	  if (commands === "L") {
21	    return { ...rover, heading: leftTurn[rover.heading] };
22	  }
23	  return rover;
24	}
